fn qr(n: i64, d: i64) -> Q { Q::new(BigInt::from(n), BigInt::from(d)) }

/// Base fee for notarization (burned).
pub const BASE_FEE: (i64, i64) = (1, 100); // 0.01 $SAI

/// Base reward per K-step (minted).
