/// A CoherenceCertificate NFT.
#[derive(Debug, Clone)]
pub struct CoherenceCertificate {
    pub id: u64,
    pub k_index: u64,
    pub rcf_majority: [u8; 32],
    pub entity_count: u32,
    pub resonance_quality: Q, // fraction of entities that passed resonance
    pub minted_at_block: u64,
    pub burned: bool,
    pub owner_entity_id: u32,
}

impl NftRegistry {
    pub fn new() -> Self { Self { certificates: Vec::new() } }

    /// Mint a CoherenceCertificate at Resonance Peak.
    pub fn mint_certificate(
        &mut self,
        k_index: u64,
        rcf_majority: [u8; 32],
        entity_count: u32,
        resonance_quality: Q,
        block_height: u64,
        owner: u32,
    ) -> u64 {
        let id = self.certificates.len() as u64;
        self.certificates.push(CoherenceCertificate {
            id, k_index, rcf_majority, entity_count, resonance_quality,
            minted_at_block: block_height, burned: false, owner_entity_id: owner,
        });
        id
    }

    /// Burn an NFT and return its $SAI value.
    /// nft_value = base × resonance_quality × mesh_size_factor
    pub fn burn_certificate(&mut self, id: u64) -> Option<Q> {
        let cert = self.certificates.get_mut(id as usize)?;
        if cert.burned { return None; }
        cert.burned = true;
        let base = qr(BASE_NFT_VALUE.0, BASE_NFT_VALUE.1);
        let mesh_factor = qr(cert.entity_count as i64, 101); // normalized to N=101
        let value = &base * &cert.resonance_quality * &mesh_factor;
        Some(value)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::constants::DISC_NORMAL;

    fn test_receipt(entity_id: u32, k: u64, sluice: u8, t_numer: i64, t_denom: u64) -> MeshReceipt {
        MeshReceipt {
            rcf_identity: [0; 32], t_k_q1616: 0, entity_id, k_index: k,
            parent_hash: [0; 16], disc_flag: DISC_NORMAL, receipt_hash: [0; 32],
            sigma_enc: 0, sluice_state: sluice,
            gap_t_k_numer: 0, gap_t_k_denom: 1,
            t_k_numer: t_numer, t_k_denom: t_denom,
            timestamp_ns: 0, telemetry: crate::ledger::ChronoTelemetry::unattached(),
            thought: crate::ledger::ThoughtTelemetry::unattached(),
            dimensional: crate::ledger::DimensionalTelemetry::unattached(),
        }
    }

    #[test]
    fn test_token_mint_and_balance() {
        let mut ts = TokenState::new();
        ts.mint(1, &qr(10, 1));
        assert_eq!(ts.balance(1), qr(10, 1));
        assert_eq!(ts.total_supply, qr(10, 1));
    }

    #[test]
    fn test_token_burn() {
        let mut ts = TokenState::new();
        ts.mint(1, &qr(10, 1));
        let burned = ts.burn(1, &qr(3, 1));
        assert_eq!(burned, qr(3, 1));
        assert_eq!(ts.balance(1), qr(7, 1));
    }

    #[test]
    fn test_process_receipt_with_improvement() {
        let mut ts = TokenState::new();
        ts.mint(1, &qr(1, 1)); // seed balance for fees
        // Receipt with negative coherence delta (improvement)
        let r = test_receipt(1, 5, 0x01, -1, 10); // t_k = -1/10 = coherence improved
        ts.process_receipt(&r);
        // Should have earned reward minus fee
        let bal = ts.balance(1);
        assert!(bal > Q::zero(), "Improving receipt should earn net positive");
    }

    #[test]
    fn test_block_close_distribution() {
        let mut ts = TokenState::new();
        let receipts = vec![
            test_receipt(1, 1, 0x01, 1, 1), // entity 1 accepted
            test_receipt(1, 2, 0x01, 1, 1), // entity 1 accepted
            test_receipt(2, 3, 0x01, 1, 1), // entity 2 accepted
        ];
        ts.process_block_close(&receipts);
        // Entity 1 contributed 2/3, Entity 2 contributed 1/3
        assert!(ts.balance(1) > ts.balance(2));
    }

    #[test]
    fn test_nft_mint_and_burn() {
        let mut nfts = NftRegistry::new();
        let mut ts = TokenState::new();
        let id = nfts.mint_certificate(100, [0x42; 32], 101, qr(90, 100), 1, 1);
        assert_eq!(id, 0);
        let value = nfts.burn_certificate(id).unwrap();
        assert!(value > Q::zero());
        ts.mint(1, &value);
        assert!(ts.balance(1) > Q::zero());
        // Cannot burn twice
        assert!(nfts.burn_certificate(id).is_none());
    }
}
